  | boolean;
type ColumnSharedType<TRecord> = {
  title?:
    | React.ReactNode
    | ((ctx: { table: Table<TRecord> }) => React.ReactNode);
  key?: string;
  className?: string;
  hidden?: boolean;
  fixed?: FixedType;
  align?: AlignType;

  // own
  classNames?: {
    head?: string;
    cell?: string;
  };

  // width?: number;
  minWidth?: number;

  enableResizing?: boolean;
  enableHiding?: boolean;

  responsive?: Breakpoint[];

  styles?: {
    head?: React.CSSProperties;
    cell?:
      | React.CSSProperties
      | ((ctx: {
          record: TRecord;
          index: number;
          row: Row<TRecord>;
          column: Column<TRecord>;
        }) => React.CSSProperties);
  };
  attributes?: Record<string, string>;
  headAttributes?: Record<string, string>;
  // rowName?: string | ((record: TRecord, index: number) => string);

  onHeaderCell?: GetComponentProps<ColumnsType<TRecord>[number]>;
  ellipsis?: CellEllipsisType;
};

