export const transformColumnDefs = <TRecord extends AnyObject>(
  columns: ColumnsType<TRecord>,
  props: Pick<OwnTableProps<TRecord>, "rowKey" | "rowSelection" | "expandable">,
  _isNotFirstDeepColumn = true,
): TTColumnDef<TRecord>[] => {
  const columnsDef: TTColumnDef<TRecord>[] = columns.map(
    (columnProp, columnIndex) => {
      const column = columnProp as ColumnType<TRecord> & {
        children?: ColumnsType<TRecord>;
      };
      const {
        key,
        children,
        dataIndex,
        enableResizing,
        enableHiding,
        title,
        width,
        minWidth,
        render,

        // meta props
        // align,
        fixed,
        // className,
        // classNames,
        // styles,
        // defaultSortOrder,
        sorter,
        // attributes,
        // headAttributes,
        // onHeaderCell,

        ...restProps
      } = column;
      const columnDefMerged: TTColumnDef<TRecord> = {
        // accessorKey: dataIndex,
        ...(typeof dataIndex === "string"
          ? { id: key ?? dataIndex, accessorKey: dataIndex }
          : {
              id: key ?? columnIndex.toString(),
              accessorFn: () => key ?? columnIndex.toString(),
            }),
        header: ({ table }) =>
          typeof title === "function" ? title({ table }) : title,
        ...(children
          ? {
              columns: transformColumnDefs(
                // add fixed to children
                children.map((x) => ({ ...x, fixed })),
                props,
                columnIndex === 0 || false,
              ),
              // for use in Gantt
              children: transformColumnDefs(
                // add fixed to children
                children.map((x) => ({ ...x, fixed })),
                props,
              ),
            }
          : {}),
        enableResizing,
        enableHiding,
        size: typeof width === "number" ? width : undefined,
        minSize: minWidth,
        meta: column,
        // sorting
        ...(sorter
          ? {
              enableSorting: true,
              sortingFn:
                typeof sorter === "string"
                  ? sorter
                  : typeof sorter === "function"
                    ? (rowA, rowB) => sorter(rowA.original, rowB.original)
                    : // object
                      typeof sorter === "object"
                      ? "compare" in sorter
                        ? typeof sorter.compare === "boolean"
                          ? () => 0
                          : (rowA, rowB) =>
                              (
                                sorter.compare as (
                                  a: TRecord,
                                  b: TRecord,
                                ) => number
                              )(rowA.original, rowB.original)
                        : "auto"
                      : // boolean
                        "auto",
            }
          : { enableSorting: false }),
        ...restProps,
        cell: ({ column, row, getValue, table }) => {
          // First data column should have expand icon + indent
          const isFirstDataColumn = columnIndex === 0;
          const hasTreeData =
            props.expandable &&
            !props.expandable.expandedRowRender &&
            (row.depth > 0 || row.getCanExpand());

          // Cell Content - render function can return ReactNode or RenderedCell
          const cellContent = (
            render
              ? typeof dataIndex === "string"
                ? render(getValue() as never, row.original, row.index, {
                    table,
                    column,
                    row,
                  })
                : render(undefined as never, row.original, row.index, {
                    table,
                    column,
                    row,
                  })
              : (getValue() as ReactNode)
          ) as React.ReactNode;

          // Only wrap with flex container if first column has tree data
          if (isFirstDataColumn && hasTreeData) {
            return (
              <div
                data-slot="table-row-content"
                className="flex items-center gap-1"
              >
                {/* Tree Data: Indent (only on first column, only children) */}
                {row.depth > 0 && (
                  <span
                    data-slot={`table-row-indent-level-${row.depth}`}
                    aria-hidden="true"
                    style={{
                      paddingLeft: `${row.depth * (props.expandable?.indentSize ?? 15)}px`,
                    }}
                  />
                )}
                {/* Tree Data: Expand Icon (only on first column) */}
                <span className="inline-block w-6">
                  {row.getCanExpand() && props.expandable?.expandIcon
                    ? props.expandable.expandIcon({
                        record: row.original,
                        expanded: row.getIsExpanded(),
                        expandable: row.getCanExpand(),
                        onExpand: row.getToggleExpandedHandler(),
                      })
                    : null}
                </span>
                {cellContent}
              </div>
            );
          }

          // Regular cell without wrapper
          return cellContent;
        },
      };

      return columnDefMerged;
    },
  );

  // if (props.rowSelection) {
  //   let lastSelectedId = "";

  //   const selectionColumn: TTColumnDef<TRecord> = {
  //     id: "selection",
  //     header: ({ table }) => {
  //       const originNode = (
  //         <Checkbox
  //           aria-label="Select all"
  //           className="flex items-center justify-center"
  //           checked={table.getIsAllPageRowsSelected()}
  //           indeterminate={table.getIsSomePageRowsSelected()}
  //           onChange={table.toggleAllPageRowsSelected}
