  //             originNode,
  //           })
  //         : originNode;
  //     },
  //     cell: ({ row, table }) => {
  //       const originNode = (
  //         <Checkbox
  //           aria-label="Select row"
  //           className="flex items-center justify-center"
  //           checked={row.getIsSelected()}
  //           disabled={!row.getCanSelect()}
  //           onChange={row.getToggleSelectedHandler()}
  //           onClick={(event) => {
  //             if (event.shiftKey) {
  //               const { rows, rowsById } = table.getRowModel();
  //               const rowsToToggle = getRowRange(rows, row.id, lastSelectedId);
  //               const isLastSelected =
  //                 rowsById[lastSelectedId]?.getIsSelected();
  //               for (const row of rowsToToggle)
  //                 row.toggleSelected(isLastSelected);
  //             }

  //             lastSelectedId = row.id;
  //           }}
  //         />
  //       );
  //       return props.rowSelection?.renderCell
  //         ? props.rowSelection.renderCell({
  //             checked: row.getIsSelected(),
  //             record: row.original,
  //             index: row.index,
  //             originNode,
  //           })
  //         : originNode;
  //     },
  //     size: 32,
  //     minSize: 32,
  //     meta: {
  //       align: "center",
  //     },
  //     enableSorting: false,
  //     enableHiding: false,
  //   };
  //   columnsDef.unshift(selectionColumn);
  // }

  // if (props.expandable) {
  //   const expandColumn: TTColumnDef<TRecord> = {
  //     id: "expander",
  //     size: 50,
  //     meta: {
